#!/usr/bin/env python3
"""
ParentWatch - Setup Script
Run this script to create all ParentWatch files in the current directory.
Usage: python3 setup_parentwatch.py
"""

import os
import base64
import stat

FILES = {}

FILES['monitor_agent.py'] = ''

FILES['dashboard.html'] = ''

FILES['START_MONITOR.bat'] = 'QGVjaG8gb2ZmCnRpdGxlIFBhcmVudFdhdGNoIC0gUnVubmluZyBpbiBiYWNrZ3JvdW5kCmNkIC9kICIlfmRwMCIKcHl0aG9uIG1vbml0b3JfYWdlbnQucHkKcGF1c2UK'

FILES['install_autostart_windows.bat'] = ''

FILES['start_monitor.sh'] = 'IyEvYmluL2Jhc2gKY2QgIiQoZGlybmFtZSAiJDAiKSIKZWNobyAiU3RhcnRpbmcgUGFyZW50V2F0Y2guLi4iCnB5dGhvbjMgbW9uaXRvcl9hZ2VudC5weQo='

FILES['README.txt'] = ''


def main():
    print("=" * 50)
    print("  ParentWatch Setup")
    print("=" * 50)
    print()
    for filename, b64content in FILES.items():
        content = base64.b64decode(b64content).decode('utf-8')
        with open(filename, 'w', encoding='utf-8') as f:
            f.write(content)
        if filename.endswith('.sh'):
            os.chmod(filename, os.stat(filename).st_mode | stat.S_IEXEC | stat.S_IXGRP | stat.S_IXOTH)
        print(f"  ✅ Created: {filename}")
    print()
    print("All files created! Now run:")
    print("  Windows : START_MONITOR.bat")
    print("  Mac/Linux: ./start_monitor.sh")
    print()
    print("Then open on your Smart TV: http://<laptop-ip>:8765")

if __name__ == '__main__':
    main()
